
<?php
require_once __DIR__ . '/../includes/session.php';
require_once __DIR__ . '/../includes/db.php';
require_role('admin');

function parse_money_value(?string $value): float {
    $normalized = strtolower(trim((string)$value));
    if ($normalized === '') return 0.0;
    $multiplier = 1.0;
    if (preg_match('/\b(cr|crore|crores)\b/', $normalized)) $multiplier = 10000000.0;
    elseif (preg_match('/\b(lpa|lac|lakh|lakhs)\b/', $normalized)) $multiplier = 100000.0;
    elseif (preg_match('/\b(m|mn|million)\b/', $normalized)) $multiplier = 1000000.0;
    elseif (preg_match('/\b(k|thousand)\b/', $normalized)) $multiplier = 1000.0;
    if (!preg_match('/(\d+(?:\.\d+)?)/', $normalized, $matches)) return 0.0;
    return ((float)$matches[1]) * $multiplier;
}

function format_compact_inr(float $amount): string {
    if ($amount >= 10000000) return '₹' . rtrim(rtrim(number_format($amount / 10000000, 2), '0'), '.') . 'Cr';
    if ($amount >= 100000) return '₹' . rtrim(rtrim(number_format($amount / 100000, 2), '0'), '.') . 'L';
    if ($amount >= 1000) return '₹' . rtrim(rtrim(number_format($amount / 1000, 2), '0'), '.') . 'K';
    return '₹' . number_format($amount, 0);
}

function detect_risk_level(array $item, string $type): array {
    $score = 0;
    $reasons = [];
    if ($type === 'student' || $type === 'company') {
        $email = strtolower((string)($item['email'] ?? ''));
        if ($email === '' || !str_contains($email, '@')) { $score += 35; $reasons[] = 'invalid email'; }
        if (!preg_match('/^[a-z0-9._%+\-]+@[a-z0-9.\-]+\.[a-z]{2,}$/', $email)) { $score += 20; $reasons[] = 'email format risk'; }
    }
    if ($type === 'company') {
        if (preg_match('/\b(test|fake|demo|spam)\b/i', (string)($item['name'] ?? ''))) { $score += 30; $reasons[] = 'suspicious company name'; }
    }
    if ($type === 'job') {
        $title = strtolower((string)($item['title'] ?? ''));
        if ($title === '' || strlen($title) < 4) { $score += 35; $reasons[] = 'weak title'; }
        if (preg_match('/\b(urgent money|pay and join|click|whatsapp|telegram)\b/i', $title)) { $score += 45; $reasons[] = 'suspicious keywords'; }
    }
    if ($score >= 60) return ['level' => 'HIGH', 'color' => '#8f2f2f', 'bg' => '#f8d6d6', 'reasons' => $reasons];
    if ($score >= 30) return ['level' => 'MEDIUM', 'color' => '#7a5c22', 'bg' => '#efe7d6', 'reasons' => $reasons];
    return ['level' => 'LOW', 'color' => '#1f6d45', 'bg' => '#dff0e4', 'reasons' => $reasons];
}

function resume_score_for_admin(array $row): int {
    $skills = array_values(array_filter(array_map('trim', explode(',', (string)($row['skills'] ?? '')))));
    return min(100, (int) min(40, round(((float)($row['cgpa'] ?? 0)) * 4)) + (!empty($row['resume_path']) ? 20 : 0) + min(24, count($skills) * 6) + (!empty($row['linkedin_url']) ? 8 : 0) + (!empty($row['github_url']) ? 8 : 0));
}

$pendingStudents = $pdo->query("SELECT id, name, email, created_at FROM users WHERE role='student' AND status='pending' ORDER BY created_at DESC LIMIT 10")->fetchAll();
$pendingCompanies = $pdo->query("SELECT id, name, email, created_at FROM users WHERE role='company' AND status='pending' ORDER BY created_at DESC LIMIT 10")->fetchAll();
$pendingJobs = $pdo->query("SELECT MAX(j.id) AS id, j.title, c.company_name, MAX(j.created_at) AS created_at FROM jobs j JOIN companies c ON c.user_id=j.company_id WHERE j.status='pending' GROUP BY j.company_id, j.title, c.company_name ORDER BY created_at DESC LIMIT 10")->fetchAll();
foreach ($pendingStudents as &$studentPending) { $studentPending['risk'] = detect_risk_level($studentPending, 'student'); } unset($studentPending);
foreach ($pendingCompanies as &$companyPending) { $companyPending['risk'] = detect_risk_level($companyPending, 'company'); } unset($companyPending);
foreach ($pendingJobs as &$jobPending) { $jobPending['risk'] = detect_risk_level($jobPending, 'job'); } unset($jobPending);

$applications = $pdo->query("SELECT a.id, u.name AS student_name, j.title AS job_title, c.company_name, a.status, a.applied_at, COALESCE(sp.branch, 'Unknown') AS campus, COALESCE(sp.cgpa, 0) AS cgpa, COALESCE(sp.skills, '') AS skills, COALESCE(sp.resume_path, '') AS resume_path, COALESCE(sp.linkedin_url, '') AS linkedin_url, COALESCE(sp.github_url, '') AS github_url FROM applications a JOIN users u ON u.id=a.student_id JOIN jobs j ON j.id=a.job_id JOIN companies c ON c.user_id=j.company_id LEFT JOIN student_profiles sp ON sp.user_id=u.id ORDER BY a.applied_at DESC LIMIT 12")->fetchAll();
foreach ($applications as &$application) { $application['resume_score'] = resume_score_for_admin($application); }
unset($application);

$interviews = $pdo->query("SELECT i.id, u.name AS student_name, j.title AS job_title, i.scheduled_at, i.mode, COALESCE(c.hr_name, c.company_name) AS interviewer_name, a.status AS application_status FROM interviews i JOIN applications a ON a.id=i.application_id JOIN users u ON u.id=a.student_id JOIN jobs j ON j.id=a.job_id JOIN companies c ON c.user_id=j.company_id ORDER BY i.scheduled_at DESC LIMIT 12")->fetchAll();
foreach ($interviews as &$interview) {
    $scheduledTs = strtotime((string)$interview['scheduled_at']);
    $interview['interview_status'] = $scheduledTs > time() ? 'Scheduled' : (strtolower((string)$interview['application_status']) === 'interviewing' ? 'Missed' : 'Completed');
    $interview['feedback_status'] = strtolower((string)$interview['application_status']) === 'interviewing' ? 'Pending' : 'Updated';
}
unset($interview);

$offers = $pdo->query("SELECT o.id, u.name AS student_name, j.title AS job_title, c.company_name, o.ctc_offered, o.status, o.issued_at FROM offers o JOIN applications a ON a.id=o.application_id JOIN users u ON u.id=a.student_id JOIN jobs j ON j.id=a.job_id JOIN companies c ON c.user_id=j.company_id ORDER BY o.issued_at DESC LIMIT 12")->fetchAll();
foreach ($offers as &$offer) {
    $issuedAt = !empty($offer['issued_at']) ? strtotime((string)$offer['issued_at']) : null;
    $offer['expiry_date'] = $issuedAt ? date('Y-m-d', strtotime('+7 days', $issuedAt)) : 'Not set';
    $offer['joining_status'] = match (strtolower((string)$offer['status'])) { 'issued' => 'Awaiting joining', 'rejected' => 'Declined', default => 'Pending' };
}
unset($offer);

$totalStudents = (int)$pdo->query("SELECT COUNT(*) FROM users WHERE role='student'")->fetchColumn();
$approvedStudents = (int)$pdo->query("SELECT COUNT(*) FROM users WHERE role='student' AND status='approved'")->fetchColumn();
$pendingStudentsCount = (int)$pdo->query("SELECT COUNT(*) FROM users WHERE role='student' AND status='pending'")->fetchColumn();
$rejectedStudents = (int)$pdo->query("SELECT COUNT(*) FROM users WHERE role='student' AND status='rejected'")->fetchColumn();
$totalCompanies = (int)$pdo->query("SELECT COUNT(*) FROM users WHERE role='company'")->fetchColumn();
$approvedCompanies = (int)$pdo->query("SELECT COUNT(*) FROM users WHERE role='company' AND status='approved'")->fetchColumn();
$pendingCompaniesCount = (int)$pdo->query("SELECT COUNT(*) FROM users WHERE role='company' AND status='pending'")->fetchColumn();
$rejectedCompanies = (int)$pdo->query("SELECT COUNT(*) FROM users WHERE role='company' AND status='rejected'")->fetchColumn();
$totalJobs = (int)$pdo->query("SELECT COUNT(*) FROM (SELECT company_id, LOWER(TRIM(title)) AS title_key FROM jobs GROUP BY company_id, title_key) t")->fetchColumn();
$approvedJobs = (int)$pdo->query("SELECT COUNT(*) FROM (SELECT company_id, LOWER(TRIM(title)) AS title_key FROM jobs WHERE status='approved' GROUP BY company_id, title_key) t")->fetchColumn();
$pendingJobsCount = (int)$pdo->query("SELECT COUNT(*) FROM (SELECT company_id, LOWER(TRIM(title)) AS title_key FROM jobs WHERE status='pending' GROUP BY company_id, title_key) t")->fetchColumn();
$rejectedJobs = (int)$pdo->query("SELECT COUNT(*) FROM (SELECT company_id, LOWER(TRIM(title)) AS title_key FROM jobs WHERE status='rejected' GROUP BY company_id, title_key) t")->fetchColumn();
$activeUsersDaily = (int)$pdo->query("SELECT COUNT(DISTINCT actor_id) FROM (SELECT a.student_id AS actor_id, a.applied_at AS activity_at FROM applications a UNION ALL SELECT a.student_id AS actor_id, i.scheduled_at AS activity_at FROM interviews i JOIN applications a ON a.id=i.application_id UNION ALL SELECT j.company_id AS actor_id, j.created_at AS activity_at FROM jobs j) activity WHERE activity_at >= DATE_SUB(NOW(), INTERVAL 1 DAY)")->fetchColumn();
$activeUsersWeekly = (int)$pdo->query("SELECT COUNT(DISTINCT actor_id) FROM (SELECT a.student_id AS actor_id, a.applied_at AS activity_at FROM applications a UNION ALL SELECT a.student_id AS actor_id, i.scheduled_at AS activity_at FROM interviews i JOIN applications a ON a.id=i.application_id UNION ALL SELECT j.company_id AS actor_id, j.created_at AS activity_at FROM jobs j) activity WHERE activity_at >= DATE_SUB(NOW(), INTERVAL 7 DAY)")->fetchColumn();
$pendingApprovalDays = (float)$pdo->query("SELECT COALESCE(AVG(TIMESTAMPDIFF(HOUR, created_at, NOW())) / 24, 0) FROM users WHERE role IN ('student','company') AND status='pending'")->fetchColumn();
$pendingJobDays = (float)$pdo->query("SELECT COALESCE(AVG(TIMESTAMPDIFF(HOUR, created_at, NOW())) / 24, 0) FROM jobs WHERE status='pending'")->fetchColumn();
$approvalEfficiency = ['students_avg_hours' => round($pendingStudentsCount ? ($pendingApprovalDays * 24) : 0, 1), 'companies_avg_hours' => round($pendingCompaniesCount ? ($pendingApprovalDays * 24) : 0, 1), 'jobs_avg_hours' => round($pendingJobsCount ? ($pendingJobDays * 24) : 0, 1), 'rejection_rate' => round((($rejectedStudents + $rejectedCompanies + $rejectedJobs) / max(1, $totalStudents + $totalCompanies + $totalJobs)) * 100, 1), 'pending_duration_days' => round(max($pendingApprovalDays, $pendingJobDays), 1)];
$placementsIssued = (int)$pdo->query("SELECT COUNT(*) FROM offers WHERE status='issued'")->fetchColumn();
$placedStudentsCount = (int)$pdo->query("SELECT COUNT(DISTINCT a.student_id) FROM offers o JOIN applications a ON a.id=o.application_id WHERE o.status='issued'")->fetchColumn();
$placementRate = round(($placedStudentsCount / max(1, $approvedStudents)) * 100, 1);
$unplacedStudentsCount = max(0, $approvedStudents - $placedStudentsCount);
$offerValues = array_values(array_filter(array_map(static fn(array $offer): float => parse_money_value($offer['ctc_offered'] ?? ''), $offers)));
$averageCtc = $offerValues ? array_sum($offerValues) / count($offerValues) : 0;
$highestPackage = $offerValues ? max($offerValues) : 0;
$flaggedCompanies = $rejectedCompanies;
$suspiciousJobs = $rejectedJobs;
$duplicateApplications = (int)$pdo->query("SELECT COUNT(*) FROM (SELECT student_id, job_id, COUNT(*) AS total_rows FROM applications GROUP BY student_id, job_id HAVING COUNT(*) > 1) duplicates")->fetchColumn();
$blacklistedUsers = (int)$pdo->query("SELECT COUNT(*) FROM users WHERE status='rejected'")->fetchColumn();
$pendingAlerts = [];
if (($pendingStudentsCount + $pendingCompaniesCount + $pendingJobsCount) >= 5) $pendingAlerts[] = 'High pending approvals queue detected.';
if ($pendingJobsCount > 0 && $approvalEfficiency['jobs_avg_hours'] >= 24) $pendingAlerts[] = 'Some jobs have been awaiting moderation for more than a day.';
if ($activeUsersDaily > max(3, (int)ceil($activeUsersWeekly / 7) * 2)) $pendingAlerts[] = 'Application activity spiked above the normal daily trend.';
if (($flaggedCompanies + $suspiciousJobs + $blacklistedUsers) > 0) $pendingAlerts[] = 'Quality monitoring needs review for flagged entities.';
if (!$pendingAlerts) $pendingAlerts[] = 'Platform health looks stable right now.';
$recentActivity = [];
$recentRegistrations = $pdo->query("SELECT name, role, status, created_at FROM users ORDER BY created_at DESC LIMIT 5")->fetchAll();
foreach ($recentRegistrations as $registration) {
    $recentActivity[] = ['label' => ucfirst((string)$registration['role']) . ' registration', 'detail' => (string)$registration['name'] . ' is currently ' . strtolower((string)$registration['status']), 'time' => (string)$registration['created_at']];
}
$recentApplications = $pdo->query("SELECT u.name AS student_name, j.title AS job_title, a.applied_at FROM applications a JOIN users u ON u.id=a.student_id JOIN jobs j ON j.id=a.job_id ORDER BY a.applied_at DESC LIMIT 5")->fetchAll();
foreach ($recentApplications as $recentApplication) {
    $recentActivity[] = ['label' => 'Application received', 'detail' => (string)$recentApplication['student_name'] . ' applied to ' . (string)$recentApplication['job_title'], 'time' => (string)$recentApplication['applied_at']];
}
usort($recentActivity, static fn(array $left, array $right): int => strcmp($right['time'], $left['time']));
$recentActivity = array_slice($recentActivity, 0, 8);
$companyPlacementCounts = $pdo->query("SELECT c.company_name, COUNT(o.id) AS placements FROM offers o JOIN applications a ON a.id=o.application_id JOIN jobs j ON j.id=a.job_id JOIN companies c ON c.user_id=j.company_id WHERE o.status='issued' GROUP BY c.company_name ORDER BY placements DESC LIMIT 5")->fetchAll();
$campusPerformance = $pdo->query("SELECT COALESCE(sp.branch, 'Unknown') AS campus, COUNT(a.id) AS applications_count FROM applications a JOIN users u ON u.id=a.student_id LEFT JOIN student_profiles sp ON sp.user_id=u.id GROUP BY COALESCE(sp.branch, 'Unknown') ORDER BY applications_count DESC LIMIT 5")->fetchAll();
$adminCount = (int)$pdo->query("SELECT COUNT(*) FROM users WHERE role='admin'")->fetchColumn();
$subAdminCount = max(0, $adminCount - 1);
$adminInitial = strtoupper(substr((string)($_SESSION['name'] ?? 'A'), 0, 1));
$adminName = (string)($_SESSION['name'] ?? 'Admin');
$notifCountStmt = $pdo->prepare('SELECT COUNT(*) FROM notifications WHERE user_id=? AND is_read=0');
$notifCountStmt->execute([(int)$_SESSION['user_id']]);
$notifCount = (int)$notifCountStmt->fetchColumn();
?>
