e;color:#8a7f72} .toolbar input,.toolbar select{width:100%;height:40px;border:1px solid #e3dacd;border-radius:10px;background:#fff;padding:0 10px;color:#675d50} .table-wrap{overflow:auto} table{width:100%;border-collapse:collapse} th,td{padding:10px;border-bottom:1px solid #eee3d6;text-align:left;font-size:13px;vertical-align:top} th{font-size:11px;color:#7f7667;text-transform:uppercase;letter-spacing:.08em} .activity-list,.chart-list{display:grid;gap:10px} .activity-item{padding:12px;border-radius:10px;background:#faf5ed;border:1px solid #efe5d8} .activity-head{display:flex;justify-content:space-between;gap:10px;font-size:13px;font-weight:800;color:#2b241b} .activity-time{font-size:11px;color:#8a7f72} .chart-row{display:grid;grid-template-columns:150px 1fr auto;gap:10px;align-items:center} .chart-label{font-size:12px;font-weight:700;color:#6f6658} .chart-bar{height:10px;background:#f0e6d8;border-radius:999px;overflow:hidden} .chart-fill{height:100%;background:linear-gradient(90deg,#b58355,#e0bc71)} .reports a{font-size:12px;font-weight:800;color:#7b5727;text-decoration:none;margin-right:14px;text-transform:uppercase;letter-spacing:.06em} @media (max-width:1200px){.stats,.insights-grid,.toolbar{grid-template-columns:repeat(2,minmax(0,1fr))}.split{grid-template-columns:1fr}} @media (max-width:1024px){.sidebar{display:none}.main{margin-left:0;padding-bottom:52px}.admin-footer{left:0}.top-logo{display:block}.top-brand{font-size:18px}.stats,.insights-grid,.toolbar{grid-template-columns:1fr}} @media (max-width:768px){.top{padding:10px 12px}.top-brand{font-size:17px}.content{padding:12px}.hero{align-items:flex-start;flex-direction:column}.hero h1{font-size:30px}.stats{grid-template-columns:1fr}.insights-grid{grid-template-columns:1fr}.toolbar{grid-template-columns:1fr}.split{grid-template-columns:1fr}.card,.insight-card{padding:12px}th,td{padding:8px;font-size:12px}.admin-footer{position:static;padding:12px;margin-top:12px}}
